var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"채굴은 아직 멀었나? 이터니움 냄새를 맡은 놈들이 언제 나타날지 모른다고.","JPN":"採掘はまだか？　エタニウムの匂いをかいだやつらが、いつ現れるかわからないんだ。","ENG":"How long will the mining take? You never know when the dogs are going to sniff out the Eternium here.","TWN":"還沒採完嗎？那些聞到永恆之金味道的傢伙不知道何時會冒出來。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"광맥을 찾는다고 끝난 게 아니니 좀 기다려. 그래서 우리가 당신들을 고용한 거잖아.","JPN":"鉱脈を探すだけでいいもんじゃないから少し待て。だから俺らがアンタたちを雇ったんだ。","ENG":"Finding a vein doesn't mean it's over. Besides, that's why we hired you.","TWN":"不是找到礦脈就好了，有點耐心好嗎？就是因為有風險我們才會花錢請你們來不是嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"침식체를 겁내면서 어떻게 헌터가 될 생각을 한 거야?","JPN":"侵食体を怖がるくせに、どうしてハンターになろうと思ったんだ？","ENG":"How are you a hunter when you're so afraid of C.O.s?","TWN":"這麼怕侵蝕體還當什麼獵人？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"침식체만 나타나면 다행이지. 동부 해역엔 더 번거로운 녀석들이 있다고.","JPN":"現れるのが侵食体だけならマシだよ。東部の海域にはもっと厄介なやつらがいるんだ。","ENG":"C.O.s aren't the biggest problem here. There are worse things to look out for in the east coast.","TWN":"只有侵蝕體出現還算小事，東部海域還有更棘手的傢伙。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"크하하핫-!","JPN":"クハハハー！","ENG":"Bwa hah hah hah!","TWN":"哇哈哈哈-！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"음? 보트소리?","JPN":"ん？　ボートの音？","ENG":"Huh? Boat sounds?","TWN":"嗯？是汽艇的聲音？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"말하기 무섭게 나타났군.","JPN":"言ってるそばから来やがったな。","ENG":"Speak of the devil.","TWN":"說曹操曹操到呢。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"어이, 누가 멋대로 여기서 채굴을 해도 된다고 했지?","JPN":"おい、誰がここで勝手に採掘していいって言った？","ENG":"Hey, who gave you permission to mine here, huh?!","TWN":"喂，誰準你們在這邊採括的？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"누구긴 누구겠어? 이쪽은 엄연히 관리국의 허가를 받고 일하는 입장이다.","JPN":"誰でもないだろうが！　こっちはちゃんと管理局の許可を得て働いているんだ。","ENG":"Who do you think? We're here under the Administration's authorization.","TWN":"還有誰？當然是得到管理局的許可。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"크헤헤, 관리국이 프론트베이의 바다를 헤집고 다니게 허락해줬다고?","JPN":"クヘヘ、管理局がフロントベイの海をウロチョロしても良いって許したってことか？","ENG":"Keh he he, the Administration gave you permission to run wild in the seas of Front Bay?","TWN":"嘿嘿嘿，你說管理局允許你們來前灣撒野？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"20년 전 우리 영역에 불쑥 나타나서 주인 행세를 하는 그 재수없는 녀석들 말이지?","JPN":"20年前に俺らの縄張りに勝手に現れて主人気取りするあの忌々しいやつらがね？","ENG":"You mean those jerks who just turned up in our territory 20 years ago and started acting like they owned the place?","TWN":"就是20年前以主人之姿突然出現在我們領地的混蛋嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐하는 짓이야! 그런 걸 쏘면 채굴기가 망가진다고!","JPN":"何するんだ！　そんなものを撃つと採掘機が壊れる！","ENG":"What do you think you're doing?! The excavator's going to break if you keep shooting like that!","TWN":"你在做什麼！這樣採礦機會壞掉的！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"우린 당신을 지켜주고 있는 거야.","JPN":"俺らはお前を守ってあげているんだ。","ENG":"We're just protecting y'all.","TWN":"我們是在保護你。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"그런 흉악한 물건으로 해저를 들쑤시면 바다의 분노를 사게 되거든!","JPN":"あんな凶悪なもので海底をいじくると海の怒りが降りるからな！","ENG":"You keep poking around the depths with those ugly machines, and you'll be facing the ocean's ire!","TWN":"用那種東西在海底戳戳戳，會引起大海的憤怒的！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"경고사격은 한 번뿐이다, 해적놈들. 좋은 말로 할 때 꺼져.","JPN":"警告射撃は一回だけだ、海賊ども。大人しく帰るんだ。","ENG":"There won't be a second warning, pirate scum. Get lost.","TWN":"你們這些海盜，這次只是警告而已，趁我好言相勸前快滾！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"케케케, 그럴 순 없지!","JPN":"ケケケ、それはできないな！","ENG":"Ke he he, not a chance!","TWN":"哈哈哈，恕難從命！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"얘들아! 드가자!","JPN":"野郎ども！　行くぜ！","ENG":"Let's go, boys!","TWN":"大家上！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}}]`);export{e as default};